package pe.edu.utp.tmo.service.impl; import java.time.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import pe.edu.utp.tmo.dao.RegistroTMODAO; import pe.edu.utp.tmo.report.ExcelReportGenerator; import pe.edu.utp.tmo.service.ReportService; @Service public class ReportServiceImpl implements ReportService{ private final RegistroTMODAO dao; private final ExcelReportGenerator gen; public ReportServiceImpl(RegistroTMODAO dao,ExcelReportGenerator gen){this.dao=dao;this.gen=gen;} @Transactional(readOnly=true) public byte[] excel(String correo,LocalDateTime inicio,LocalDateTime fin){return gen.generarReporteTmo(dao.listarPorPeriodo(inicio,fin));}}